#include <stdio.h>
#include <stdint.h>

// Returns base^exp if it does not exceed limit, otherwise returns limit+1.
static int64_t power_limit(int64_t base, int exp, int64_t limit) {
    int64_t result = 1;
    for (int i = 0; i < exp; ++i) {
        if (result > limit / base) return limit + 1; // would overflow or exceed limit
        result *= base;
    }
    return result;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n; int64_t m; scanf("%d %lld", &n, &m);
        int64_t low = 1, high = m, ans = -1;
        while (low <= high) {
            int64_t mid = low + (high - low) / 2;
            int64_t val = power_limit(mid, n, m);
            if (val == m) { ans = mid; break; }
            if (val < m) low = mid + 1; else high = mid - 1;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

