import java.io.*;
import java.util.*;

public class Main {
    private static long powerLimit(long base, int exp, long limit) {
        long res = 1L;
        for (int i = 0; i < exp; ++i) {
            if (res > limit / base) return limit + 1; // overflow or exceeds limit
            res *= base;
        }
        return res;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            st = new StringTokenizer(br.readLine());
            int n = Integer.parseInt(st.nextToken());
            long m = Long.parseLong(st.nextToken());
            long low = 1, high = m, ans = -1;
            while (low <= high) {
                long mid = low + (high - low) / 2;
                long val = powerLimit(mid, n, m);
                if (val == m) { ans = mid; break; }
                if (val < m) low = mid + 1; else high = mid - 1;
            }
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
}

