import sys

def power_limit(base, exp, limit):
    res = 1
    for _ in range(exp):
        if res > limit // base:
            return limit + 1
        res *= base
    return res

def nth_root(n, m):
    low, high = 1, m
    while low <= high:
        mid = (low + high) // 2
        val = power_limit(mid, n, m)
        if val == m:
            return mid
        if val < m:
            low = mid + 1
        else:
            high = mid - 1
    return -1

data = sys.stdin.read().strip().split()
if not data:
    sys.exit()
it = iter(data)
T = int(next(it))
out = []
for _ in range(T):
    n = int(next(it))
    m = int(next(it))
    out.append(str(nth_root(n, m)))
print('\n'.join(out))

